import type { ImageModelV3, SharedV3Warning } from '@ai-sdk/provider';
import type { Resolvable } from '@ai-sdk/provider-utils';
import {
  combineHeaders,
  createJsonErrorResponseHandler,
  createJsonResponseHandler,
  FetchFunction,
  parseProviderOptions,
  postJsonToApi,
  resolve,
  withoutTrailingSlash,
} from '@ai-sdk/provider-utils';
import { z } from 'zod/v4';
import type { PixelArtImageModelId } from './pixelart-image-settings';

// Internal config passed from the provider factory
interface PixelArtImageModelConfig {
  provider: string;
  baseURL: string;
  headers?: Resolvable<Record<string, string | undefined>>;
  fetch?: FetchFunction;
  _internal?: { currentDate?: () => Date };
}

// Zod schema for provider-specific options
const pixelArtImageSettingsSchema = z.object({
  size: z.string().optional(),
  style: z.enum(['pixel', 'retro', '8bit']).optional(),
  pixelDensity: z.number().optional(),
});

// Zod schema for API success response
const pixelArtImageResponseSchema = z.object({
  images: z.array(z.object({ b64_json: z.string() })),
  model: z.string().nullish(),
});

// Zod schema for API error response
const pixelArtErrorSchema = z.object({
  error: z.object({ message: z.string(), code: z.string().nullish() }),
});

const pixelArtFailedResponseHandler = createJsonErrorResponseHandler({
  errorSchema: pixelArtErrorSchema,
  errorToMessage: e => e.error.message,
});

export class PixelArtImageModel implements ImageModelV3 {
  readonly specificationVersion = 'v3';
  readonly maxImagesPerCall = 1;

  get provider(): string { return this.config.provider; }

  constructor(
    readonly modelId: PixelArtImageModelId,
    private readonly config: PixelArtImageModelConfig,
  ) {}

  async doGenerate(
    options: Parameters<ImageModelV3['doGenerate']>[0],
  ): Promise<Awaited<ReturnType<ImageModelV3['doGenerate']>>> {
    const warnings: Array<SharedV3Warning> = [];
    const currentDate = this.config._internal?.currentDate?.() ?? new Date();

    // Warn about unsupported standard options
    if (options.aspectRatio != null) {
      warnings.push({ type: 'unsupported', feature: 'aspectRatio',
        details: 'PixelArt provider does not support aspectRatio. Use size instead.' });
    }
    if (options.seed != null) {
      warnings.push({ type: 'unsupported', feature: 'seed' });
    }
    if (options.files != null && options.files.length > 0) {
      warnings.push({ type: 'unsupported', feature: 'image editing (files)' });
    }
    if (options.mask != null) {
      warnings.push({ type: 'unsupported', feature: 'mask/inpainting' });
    }

    // Parse provider-specific options
    const providerSettings = await parseProviderOptions({
      provider: 'pixelart',
      providerOptions: options.providerOptions,
      schema: pixelArtImageSettingsSchema,
    });

    // Build request body
    const requestBody: Record<string, unknown> = {
      model: this.modelId,
      prompt: options.prompt,
      n: options.n,
      size: providerSettings?.size ?? options.size,
      response_format: 'b64_json',
    };
    if (providerSettings?.style != null) requestBody.style = providerSettings.style;
    if (providerSettings?.pixelDensity != null) requestBody.pixel_density = providerSettings.pixelDensity;

    const { value, responseHeaders } = await postJsonToApi({
      url: `${this.config.baseURL}/images/generations`,
      headers: combineHeaders(await resolve(this.config.headers), options.headers),
      body: requestBody,
      failedResponseHandler: pixelArtFailedResponseHandler,
      successfulResponseHandler: createJsonResponseHandler(pixelArtImageResponseSchema),
      abortSignal: options.abortSignal,
      fetch: this.config.fetch,
    });

    return {
      images: value.images.map(img => img.b64_json),
      warnings,
      response: {
        timestamp: currentDate,
        modelId: value.model ?? this.modelId,
        headers: responseHeaders,
      },
    };
  }
}
```

