  /** PixelArt API key. Defaults to PIXELART_API_KEY env variable. */
  apiKey?: string;
  /** Override base URL. Default: https://api.pixelart.ai/v1 */
  baseURL?: string;
  /** Extra headers for every request. */
  headers?: Record<string, string>;
  /** Custom fetch implementation. */
  fetch?: FetchFunction;
}

