import type { ImageModelV3, SharedV3Warning } from '@ai-sdk/provider';
import type { Resolvable } from '@ai-sdk/provider-utils';
import {
  combineHeaders,
  convertBase64ToUint8Array,
  createJsonErrorResponseHandler,
  createJsonResponseHandler,
  FetchFunction,
  parseProviderOptions,
  postJsonToApi,
  resolve,
} from '@ai-sdk/provider-utils';
import { z } from 'zod/v4';
import { PixelArtImageModelId, PixelArtImageSettings } from './pixelart-image-settings';

/**
 * Internal configuration for the PixelArtImageModel.
 */
interface PixelArtImageModelConfig {
  provider: string;
  baseURL: string;
  headers?: Resolvable<Record<string, string | undefined>>;
  fetch?: FetchFunction;
  _internal?: {
    currentDate?: () => Date;
  };
}

/**
 * Zod schema for validating pixelart provider options passed via `providerOptions.pixelart`.
 */
const pixelArtImageSettingsSchema = z.object({
  size: z.string().optional(),
  style: z.enum(['pixel', 'retro', '8bit']).optional(),
  pixelDensity: z.number().optional(),
});

/**
 * Schema for the PixelArt image generation API response.
 */
const pixelArtImageResponseSchema = z.object({
  created: z.number().optional(),
  data: z.array(
    z.object({
      b64_json: z.string(),
    }),
  ),
});

/**
 * Schema for PixelArt API error responses.
 */
const pixelArtErrorSchema = z.object({
  error: z.object({
    message: z.string(),
    type: z.string().optional(),
    code: z.string().optional(),
  }),
});

const pixelArtFailedResponseHandler = createJsonErrorResponseHandler({
  errorSchema: pixelArtErrorSchema,
  errorToMessage: error => error.error.message,
});

/**
 * PixelArt image generation model implementing the `ImageModelV3` interface.
 */
export class PixelArtImageModel implements ImageModelV3 {
  readonly specificationVersion = 'v3';
  readonly maxImagesPerCall = 1;

  get provider(): string {
    return this.config.provider;
  }

  constructor(
    readonly modelId: PixelArtImageModelId,
    private readonly config: PixelArtImageModelConfig,
  ) {}

  async doGenerate(
    options: Parameters<ImageModelV3['doGenerate']>[0],
  ): Promise<Awaited<ReturnType<ImageModelV3['doGenerate']>>> {
    const {
      prompt,
      n,
      size,
      aspectRatio,
      seed,
      providerOptions,
      headers,
      abortSignal,
      files,
      mask,
    } = options;

    const warnings: Array<SharedV3Warning> = [];

    // Warn about unsupported standard parameters
    if (aspectRatio != null) {
      warnings.push({
        type: 'unsupported',
        feature: 'aspectRatio',
        details:
          'PixelArt does not support aspect ratio. Use `size` instead.',
      });
    }

    if (seed != null) {
      warnings.push({ type: 'unsupported', feature: 'seed' });
    }

    if (files != null && files.length > 0) {
      warnings.push({
        type: 'unsupported',
        feature: 'image',
        details:
          'PixelArt image generation does not support input images (files). ' +
          'Only text-to-image generation is supported.',
      });
    }

    if (mask != null) {
      warnings.push({
        type: 'unsupported',
        feature: 'image',
        details:
          'PixelArt image generation does not support image masks.',
      });
    }

    // Parse provider-specific options from `providerOptions.pixelart`
    const pixelArtOptions = await parseProviderOptions({
      provider: 'pixelart',
      providerOptions,
      schema: pixelArtImageSettingsSchema,
    });

    // Resolve the effective size: provider options take precedence over the standard `size`
    const effectiveSize = pixelArtOptions?.size ?? size;

    const currentDate = this.config._internal?.currentDate?.() ?? new Date();

    const { value, responseHeaders } = await postJsonToApi({
      url: `${this.config.baseURL}/images/generations`,
      headers: combineHeaders(
        await resolve(this.config.headers),
        headers,
      ),
      body: {
        model: this.modelId,
        prompt,
        n,
        response_format: 'b64_json',
        ...(effectiveSize != null ? { size: effectiveSize } : {}),
        ...(pixelArtOptions?.style != null
          ? { style: pixelArtOptions.style }
          : {}),
        ...(pixelArtOptions?.pixelDensity != null
          ? { pixel_density: pixelArtOptions.pixelDensity }
          : {}),
      },
      failedResponseHandler: pixelArtFailedResponseHandler,
      successfulResponseHandler: createJsonResponseHandler(
        pixelArtImageResponseSchema,
      ),
      abortSignal,
      fetch: this.config.fetch,
    });

    return {
      images: value.data.map(item =>
        convertBase64ToUint8Array(item.b64_json),
      ),
      warnings,
      response: {
        modelId: this.modelId,
        timestamp: currentDate,
        headers: responseHeaders,
      },
      providerMetadata: {
        pixelart: {
          created: value.created,
        },
      },
    };
  }
}

