      /**
       * A compatibility feature is used that might lead to suboptimal results.
       */
      type: 'compatibility';

      /**
       * The feature that is used in a compatibility mode.
       */
      feature: string;

      /**
       * Additional details about the warning.
       */
      details?: string;
    }
  | {
      /**
       * Other warning.
       */
      type: 'other';

      /**
       * The message of the warning.
       */
      message: string;
    };

