export type {
  PixelArtProvider,
  PixelArtProviderSettings,
} from './pixelart-provider';
export { createPixelArt, pixelart } from './pixelart-provider';
export type {
  PixelArtImageModelId,
  PixelArtImageSettings,
} from './pixelart-image-settings';
export { VERSION } from './version';

import {
  ImageModelV3,
  NoSuchModelError,
  ProviderV3,
} from '@ai-sdk/provider';
import type { FetchFunction } from '@ai-sdk/provider-utils';
import {
  loadApiKey,
  withoutTrailingSlash,
  withUserAgentSuffix,
} from '@ai-sdk/provider-utils';
import { PixelArtImageModel } from './pixelart-image-model';
import { PixelArtImageModelId } from './pixelart-image-settings';
import { VERSION } from './version';

const defaultBaseURL = 'https://api.pixelart.ai/v1';

/**
 * Configuration settings for creating a PixelArt provider instance.
 */
export interface PixelArtProviderSettings {
  /**
   * PixelArt API key. Default value is taken from the `PIXELART_API_KEY`
   * environment variable.
   */
  apiKey?: string;

  /**
   * Base URL for the PixelArt API.
   * Defaults to `https://api.pixelart.ai/v1`.
   */
  baseURL?: string;

  /**
   * Custom headers to include in every request.
   */
  headers?: Record<string, string>;

  /**
   * Custom fetch implementation. Useful as middleware to intercept requests
   * or to provide a custom fetch for testing.
   */
  fetch?: FetchFunction;
}

/**
 * PixelArt provider interface.
 *
 * Extends `ProviderV3` and exposes only image generation — no language models
 * or embedding models are supported.
 */
export interface PixelArtProvider extends ProviderV3 {
  /**
   * Creates a PixelArt image generation model.
   */
  image(modelId: PixelArtImageModelId): ImageModelV3;

  /**
   * Creates a PixelArt image generation model.
   * Alias for `image()`.
   */
  imageModel(modelId: PixelArtImageModelId): ImageModelV3;
}

/**
 * Create a PixelArt provider instance.
 *
 * @param options - Optional configuration for the provider.
 * @returns A `PixelArtProvider` instance ready to create image models.
 *
 * @example
 * ```ts
 * import { createPixelArt } from '@ai-sdk/pixelart';
 * import { generateImage } from 'ai';
 *
 * const pixelart = createPixelArt({ apiKey: process.env.PIXELART_API_KEY });
 *
 * const { images } = await generateImage({
 *   model: pixelart.image('pixelart-v1'),
 *   prompt: 'A pixel art castle at sunset',
 *   providerOptions: {
 *     pixelart: { style: 'retro', pixelDensity: 8 },
 *   },
 * });
 * ```
 */
export function createPixelArt(
  options: PixelArtProviderSettings = {},
): PixelArtProvider {
  const baseURL = withoutTrailingSlash(options.baseURL ?? defaultBaseURL);

  const getHeaders = () =>
    withUserAgentSuffix(
      {
        Authorization: `Bearer ${loadApiKey({
          apiKey: options.apiKey,
          environmentVariableName: 'PIXELART_API_KEY',
          description: 'PixelArt',
        })}`,
        ...options.headers,
      },
      `ai-sdk/pixelart/${VERSION}`,
    );

  const createImageModel = (modelId: PixelArtImageModelId) =>
    new PixelArtImageModel(modelId, {
      provider: 'pixelart.image',
      baseURL: baseURL ?? defaultBaseURL,
      headers: getHeaders,
      fetch: options.fetch,
    });

  return {
    specificationVersion: 'v3' as const,

    image: createImageModel,
    imageModel: createImageModel,

    languageModel: (modelId: string) => {
      throw new NoSuchModelError({
        modelId,
        modelType: 'languageModel',
      });
    },

    embeddingModel: (modelId: string) => {
      throw new NoSuchModelError({
        modelId,
        modelType: 'embeddingModel',
      });
    },
  };
}

/**
 * Default PixelArt provider instance.
 * Uses the `PIXELART_API_KEY` environment variable for authentication.
 */
export const pixelart = createPixelArt();

